"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[2485],{6809(i){i.exports=JSON.parse('{"tag":{"label":"open-source","permalink":"/tags/open-source","allTagsPath":"/tags","count":11,"items":[{"id":"entities/axe-os","title":"AxeOS","description":"AxeOS is the primary open-source firmware for BitAxe miners. It replaces factory firmware to provide lower latency, better pool compatibility, and advanced configuration options including DATUM support.","permalink":"/entities/axe-os"},{"id":"entities/bitaxe","title":"BitAxe","description":"BitAxe is an open-source, low-power Bitcoin ASIC miner designed for home mining. It bridges the gap between industrial-scale equipment and hobbyist participation in network security.","permalink":"/entities/bitaxe"},{"id":"entities/bluewallet","title":"BlueWallet","description":"Mobile Bitcoin wallet for iOS and Android. Supports both on-chain and Lightning. Originally included a custodial Lightning option; shifting toward non-custodial with Lightning Dev Kit (LDK) integration.","permalink":"/entities/bluewallet"},{"id":"entities/btcpay-server","title":"BTCPayServer","description":"Self-hosted, open-source payment processor for Bitcoin. Accept on-chain and Lightning payments without relying on third-party custodians.","permalink":"/entities/btcpay-server"},{"id":"entities/electrum","title":"Electrum","description":"Electrum is one of the oldest Bitcoin wallets, using SPV to verify transactions without downloading the full blockchain. Its server implementation (ElectrumX, Electrs, Fulcrum) is widely bundled with node packages.","permalink":"/entities/electrum"},{"id":"entities/payjoin-dev-kit","title":"Payjoin Development Kit (PDK)","description":"Open-source SDK for building Payjoin (BIP 78) functionality into Bitcoin wallets and applications. Maintained by Dan Gould.","permalink":"/entities/payjoin-dev-kit"},{"id":"entities/raspiblitz","title":"RaspiBlitz","description":"RaspiBlitz is a DIY Bitcoin Lightning node project built for education. Unlike commercial plug-and-play nodes, it emphasizes learning the underlying tools.","permalink":"/entities/raspiblitz"},{"id":"entities/seedsigner","title":"SeedSigner","description":"Open-source, DIY Bitcoin signing device built from commodity hardware. Designed for air-gapped seed generation, transaction signing, and multisig coordination without trusting proprietary hardware.","permalink":"/entities/seedsigner"},{"id":"entities/sparrow-wallet","title":"Sparrow Wallet","description":"Sparrow Wallet is a desktop Bitcoin wallet focused on privacy, security, and flexibility. It supports single-sig and multisig setups and is designed for users who want full control over their coins and connections.","permalink":"/entities/sparrow-wallet"},{"id":"entities/trezor","title":"Trezor","description":"Trezor is a hardware wallet developed by SatoshiLabs. The first commercial hardware wallet (2014), known for fully open-source firmware.","permalink":"/entities/trezor"},{"id":"entities/zeus","title":"Zeus","description":"Mobile Lightning wallet and node management app. Connects to your own Lightning node (LND, Core Lightning, or Eclair) remotely, giving you full control without running a node on your phone.","permalink":"/entities/zeus"}],"unlisted":false}}')}}]);